// Outputs a single canonical shape for downstream nodes.

const body = $input.first().json.body || $input.first().json;

let normalized = {
  type: null,             // 'po' | 'batch'
  action: null,           // 'approve' | 'reject'
  reference_id: null,     // 'PO-2026-0047' or 'BATCH-2026-W15'
  record_id: null,        // Airtable record id (optional; Command Center sends, Slack doesn't)
  approved_by: null,      // Human-readable name of approver
  notes: null,            // Optional rejection reason or approver note
  source: 'command_center', // 'command_center' | 'slack'
  slack_response_url: null,
  slack_message_ts: null,
  slack_channel: null
};

// Detect format
const isSlack = !!body.payload || (body.actions && Array.isArray(body.actions));

if (isSlack) {
  // Parse Slack interactive payload
  let slackPayload;
  try {
    slackPayload = typeof body.payload === 'string' ? JSON.parse(body.payload) : (body.payload || body);
  } catch (e) {
    throw new Error('Invalid Slack payload: ' + e.message);
  }

  const actionValue = slackPayload.actions?.[0]?.value || '';
  const actionId = slackPayload.actions?.[0]?.action_id || '';

  // action_id convention: "approve_po" | "reject_po" | "approve_batch" | "reject_batch"
  // action value convention: the reference_id (e.g., "PO-2026-0047" or "BATCH-2026-W15")
  // Legacy value format: "approve_BATCH-2026-W15" (WF14 existing pattern)

  let parsedAction, parsedType, parsedRef;

  if (actionId && actionId.includes('_')) {
    // New pattern: action_id = "approve_po" and value = reference_id
    const parts = actionId.split('_');
    parsedAction = parts[0];
    parsedType = parts[1];
    parsedRef = actionValue;
  } else if (actionValue.startsWith('approve_') || actionValue.startsWith('reject_')) {
    // Legacy WF14 pattern: value = "approve_BATCH-2026-W15"
    const underscoreIdx = actionValue.indexOf('_');
    parsedAction = actionValue.slice(0, underscoreIdx);
    parsedRef = actionValue.slice(underscoreIdx + 1);
    // Infer type from reference_id prefix
    parsedType = parsedRef.startsWith('PO-') ? 'po' : (parsedRef.startsWith('BATCH-') ? 'batch' : 'unknown');
  } else {
    throw new Error('Could not parse Slack action: action_id=' + actionId + ' value=' + actionValue);
  }

  normalized.type = parsedType;
  normalized.action = parsedAction;
  normalized.reference_id = parsedRef;
  normalized.approved_by = slackPayload.user?.name || slackPayload.user?.username || 'Slack User';
  normalized.source = 'slack';
  normalized.slack_response_url = slackPayload.response_url || null;
  normalized.slack_message_ts = slackPayload.message?.ts || slackPayload.container?.message_ts || null;
  normalized.slack_channel = slackPayload.channel?.id || null;
} else {
  // Command Center JSON format
  normalized.type = (body.type || '').toLowerCase();
  normalized.action = (body.action || '').toLowerCase();
  normalized.reference_id = body.reference_id || null;
  normalized.record_id = body.record_id || null;
  normalized.approved_by = body.approved_by || 'Unknown';
  normalized.notes = body.notes || null;
  normalized.source = 'command_center';
}

// Validate
if (!['po', 'batch'].includes(normalized.type)) {
  throw new Error('Invalid type. Expected "po" or "batch", got: ' + normalized.type);
}
if (!['approve', 'reject'].includes(normalized.action)) {
  throw new Error('Invalid action. Expected "approve" or "reject", got: ' + normalized.action);
}
if (!normalized.reference_id) {
  throw new Error('Missing reference_id');
}

normalized.timestamp = new Date().toISOString();
normalized.response_message = 'Approval received for ' + normalized.reference_id + ' (' + normalized.action + ')';

return [{ json: normalized }];

